-- Index for ORDER BY createdAt DESC (main feed query)
CREATE INDEX IF NOT EXISTS idx_emotion_board_posts_created_at 
  ON emotion_board_posts (createdAt DESC);

-- Index for filtering posts by userId (profile page)
CREATE INDEX IF NOT EXISTS idx_emotion_board_posts_user_id 
  ON emotion_board_posts (userId);

-- Index for correlated subquery: COUNT(*) WHERE postId = ?
CREATE INDEX IF NOT EXISTS idx_emotion_board_likes_post_id 
  ON emotion_board_likes (postId);

-- Composite index for EXISTS(postId, userId) in isLiked subquery
CREATE INDEX IF NOT EXISTS idx_emotion_board_likes_post_user 
  ON emotion_board_likes (postId, userId);

